export const homeStyles = {
    // Hero section
    hero: {
        background: 'linear-gradient(135deg, #dc2626, #991b1b)',
        color: '#fff', padding: '80px 32px', textAlign: 'center'
    },
    heroTitle: { fontSize: 42, fontWeight: 800, marginBottom: 16 },
    heroSub: { fontSize: 18, opacity: 0.9, marginBottom: 32 },
    heroButtons: { display: 'flex', gap: 12, justifyContent: 'center', flexWrap: 'wrap' },
    btnPrimary: {
        padding: '12px 32px', background: '#fff', color: '#dc2626',
        border: 'none', borderRadius: 8, fontWeight: 700,
        fontSize: 15, cursor: 'pointer'
    },
    btnOutline: {
        padding: '12px 32px', background: 'transparent', color: '#fff',
        border: '2px solid #fff', borderRadius: 8, fontWeight: 700,
        fontSize: 15, cursor: 'pointer'
    },

    // Features section
    features: { padding: '64px 32px', background: '#f9fafb', textAlign: 'center' },
    featTitle: { fontSize: 28, fontWeight: 700, marginBottom: 8, color: '#111' },
    featSub: { color: '#6b7280', marginBottom: 40, fontSize: 15 },
    featGrid: {
        display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(220px, 1fr))',
        gap: 24, maxWidth: 900, margin: '0 auto'
    },
    featCard: {
        background: '#fff', borderRadius: 10, padding: 28,
        boxShadow: '0 1px 4px rgba(0,0,0,.08)', textAlign: 'center'
    },
    featIcon: { fontSize: 36, marginBottom: 12 },
    featName: { fontWeight: 700, fontSize: 15, marginBottom: 6, color: '#111' },
    featDesc: { fontSize: 13, color: '#6b7280', lineHeight: 1.6 },

    // Footer
    footer: {
        background: '#111', color: '#9ca3af', textAlign: 'center',
        padding: '24px 32px', fontSize: 13
    },
};
